SELECT

FROM imaging_report
WHERE tenant_id = #{tenantId}
  AND encounter_id = #{encounterId}
ORDER BY id DESC

mapper.update:
UPDATE imaging_report
SET patient_id = #{patientId},
    encounter_id = #{encounterId},
    modality = #{modality},
    report_text = #{reportText},
    file_id = #{fileId},
    source_system = #{sourceSystem},
    examined_at = #{examinedAt}
WHERE tenant_id = #{tenantId}
  AND id = #{id}

mapper.delete:
DELETE
FROM imaging_report
WHERE tenant_id = #{tenantId}
  AND id = #{id}
